	"dataSources": {
		"ds_0LBHfs3r": {
			"name": "activities by user",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " | timechart count by user"
			},
			"type": "ds.chain"
		},
		"ds_1dnRSxiQ_ds_KtFg8oQ2": {
			"name": "Object Creation By Type - Pie chart search copy 1",
			"options": {
				"enableSmartSources": true,
				"extend": "ds_sxu2HJOI",
				"query": "| search object_action = create | chart count by object_type"
			},
			"type": "ds.chain"
		},
		"ds_2bG53cci_ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"name": "Logins By User Agent - Chart search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search NOT useragent = \"n/a\" AND NOT useragent=\"unknown\"\n| stats count by useragent"
			},
			"type": "ds.chain"
		},
		"ds_AXgjIFgY": {
			"name": "Activity By Object",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by object_name"
			},
			"type": "ds.chain"
		},
		"ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"name": "Activity By Host - Chart search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " | eval fields=split(host,\".\") | eval host=mvindex(fields,0) |  stats count by host"
			},
			"type": "ds.chain"
		},
		"ds_KtFg8oQ2": {
			"name": "Object Creation By Type - Pie chart search",
			"options": {
				"enableSmartSources": true,
				"extend": "ds_sxu2HJOI",
				"query": "| search object_action = create | chart count by object_type"
			},
			"type": "ds.chain"
		},
		"ds_OOnwhUDc": {
			"name": "Activity By App - Table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by app"
			},
			"type": "ds.chain"
		},
		"ds_SG2pKPV7_ds_slbguYLS_ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"name": "Logins By User Agent - Table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search NOT useragent = \"n/a\" AND NOT useragent=\"unknown\"\n| stats count by useragent"
			},
			"type": "ds.chain"
		},
		"ds_WY4obnmU": {
			"name": "Activity By User - Table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by user"
			},
			"type": "ds.chain"
		},
		"ds_eKo8k29O_ds_WY4obnmU": {
			"name": "Activity By User - Chart search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats dc(user)"
			},
			"type": "ds.chain"
		},
		"ds_nQAbGEMe": {
			"name": "events",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  eval action=user_action\n| sort -_time,\n|  eval event=orig_body\n|  eval name=object_name\n|  eval time=strftime(_time,\"%Y-%m-%d  %H:%M:%S.%Q\")\n|  fields time, user, action, name, event\n|  fields - _time"
			},
			"type": "ds.chain"
		},
		"ds_slbguYLS_ds_EkqGpKKc_ds_34ljSSqf_ds_WY4obnmU": {
			"name": "Activity By Host - Table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " |  stats count by host"
			},
			"type": "ds.chain"
		},
		"ds_sxu2HJOI": {
			"name": "ds_baseSelection",
			"options": {
				"query": "| savedsearch audit_trail_users_query ss_user_names=\"$ms_user_names$\" ss_host_names=\"$ms_host_names$\" ss_text=\"$text_token$\"\n```Tags may have mnulti values: {[0]='tag_1' [1]='tag_2'}- split it to separate events```\n| eval tagnames=split(replace(object_name, \"\\[[0-9]*\\]=\",\"\"), \"' '\") |  mvexpand tagnames | eval object_name=ltrim(rtrim(tagnames,\"'}\"),\"{'\")\n```raw attributes (redundant)```\n| search user IN ($ms_user_names$)\n| search host IN ($ms_host_names$)\n```calculated attributes```\n| search user_action IN ($ms_actions$)\n| search object_name IN ($ms_object_names$)\n| search app IN ($ms_app_names$)\n| search useragent IN ($ms_user_agents$)\n\n",
				"queryParameters": {
					"earliest": "$time.earliest$",
					"latest": "$time.latest$"
				}
			},
			"type": "ds.search"
		},
		"ds_uplRMfgR_ds_OOnwhUDc": {
			"name": "Activity By App - Chart search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats dc(app)"
			},
			"type": "ds.chain"
		},
		"ds_wVOevxkK_ds_AXgjIFgY": {
			"name": "Activity By Object - table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  eval context=object_name\n| stats count by context"
			},
			"type": "ds.chain"
		},
		"ds_yX0sUuiQ_ds_0LBHfs3r": {
			"name": "activities by action",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": " | eval the_action=IF(\"$dd_augment_action$\" == \"yes\", ex_user_action, user_action)\n | timechart count by the_action"
			},
			"type": "ds.chain"
		},
		"ds_Af3ExPjS_ds_eKo8k29O_ds_WY4obnmU": {
			"name": "Distinct stacks",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats dc(stack)"
			},
			"type": "ds.chain"
		},
		"ds_bkO5kv5T_ds_WY4obnmU": {
			"name": "Activity By Stack - Table Search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats count by stack"
			},
			"type": "ds.chain"
		},
		"ds_eWH0mViw_ds_WY4obnmU": {
			"name": "Activities - Table search",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| eval action=user_action\n| stats count by action"
			},
			"type": "ds.chain"
		},
		"ds_XvxGTFs0_ds_AXgjIFgY": {
			"name": "Users And Action",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  eval action=user_action\n|  dedup user, action\n|  table user, action \n"
			},
			"type": "ds.chain"
		},
		"ds_x2TEDIbr": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  table user_action \n|  dedup user_action"
			},
			"name": "List of Actions"
		},
		"ds_LwcvAxAb": {
			"type": "ds.chain",
			"options": {
				"query": "|  table useragent \n|  dedup useragent",
				"extend": "ds_sxu2HJOI"
			},
			"name": "List Of Useragents"
		},
		"ds_eSukAtNI": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  table object_name \n|  dedup object_name\n| eval object_name=if(match(object_name, \".*[\\s\\(\\)].*\"), \"\\\"\" . object_name . \"\\\"\", object_name)"
			},
			"name": "List of Object Names"
		},
		"ds_DUABMnxY": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  table user \n|  dedup user"
			},
			"name": "List of Users"
		},
		"ds_oUwKmA5u": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  table app \n|  dedup app"
			},
			"name": "List of Apps"
		},
		"ds_fTyQF8LC": {
			"type": "ds.chain",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  table host \n|  dedup host"
			},
			"name": "Search_1"
		},
		"ds_ir6wOG8o_ds_eKo8k29O_ds_WY4obnmU": {
			"name": "Activity By User - Chart search copy 1",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| stats dc(user)"
			},
			"type": "ds.chain"
		},
		"ds_BKJ013Yc_ds_nQAbGEMe": {
			"name": "events copy 1",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "|  eval action=user_action\n| sort -_time,\n|  eval event=orig_body\n|  eval name=object_name\n|  eval time=strftime(_time,\"%Y-%m-%d  %H:%M:%S.%Q\")\n|  fields time, user, action, name, event\n|  fields - _time\n| fields - _mkv_child"
			},
			"type": "ds.chain"
		},
		"ds_BOYrM8sc_ds_uplRMfgR_ds_OOnwhUDc": {
			"name": "Failed Logins - Single Value",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search user_action=\"login_attempt\" AND NOT info=\"succeeded\" \n|  stats count"
			},
			"type": "ds.chain"
		},
		"ds_B9ZY1Wof_ds_BOYrM8sc_ds_uplRMfgR_ds_OOnwhUDc": {
			"name": "All Logins - Single Value",
			"options": {
				"extend": "ds_sxu2HJOI",
				"query": "| search user_action=\"login_attempt\" \n|  stats count "
			},
			"type": "ds.chain"
		}
